import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.nio.file.Path;

public class PathTraversalSecure {
    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd";
        String directory = "/var/www/data/";

        // Sanitize user input to prevent directory traversal
        String sanitizedInput = userInput.replaceAll("\\.\\.", "");

        // Ensure that the resulting path is within the specified directory
        Path fullPath = Paths.get(directory, sanitizedInput).normalize();

        if (!fullPath.startsWith(directory)) {
            System.out.println("Invalid path specified");
            return;
        }

        try {
            File file = fullPath.toFile();
            byte[] fileContent = Files.readAllBytes(file.toPath());
            System.out.println(new String(fileContent));
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

